import apiClient from './api';

class AuthService {
  /**
   * 用户登录
   * @param {string} username 用户名
   * @param {string} password 密码
   * @returns {Promise} 登录结果
   */
  login(username, password) {
    return apiClient
      .post('/auth/signin', {
        username,
        password
      })
      .then(response => {
        // 标准化存储格式
        const userData = {
          ...response,
          // 兼容性处理
          accessToken: response.token || response.accessToken,
          // 确保角色信息存在
          roles: response.roles || []
        };

        // 确保角色数组正确格式化
        if (userData.roles && !Array.isArray(userData.roles)) {
          userData.roles = typeof userData.roles === 'string' ? [userData.roles] : [];
        }

        // 保存用户信息到本地存储
        localStorage.setItem('user', JSON.stringify(userData));

        return userData;
      })
      .catch(error => {
        console.log('登录错误详情:', error);
        // 打印完整错误对象的详细内容，便于调试
        console.log('错误响应数据:', error.response ? {
          status: error.response.status,
          statusText: error.response.statusText,
          data: error.response.data,
          headers: error.response.headers
        } : '无响应数据');

        // 1. 检查响应对象
        if (error.response) {
          // 2. 检查响应数据
          const responseData = error.response.data;

          // 3. 尝试多种方式判断是否是禁用账户错误
          const errorMessage = 
            (typeof responseData === 'string' ? responseData : '') || 
            (responseData?.message) || 
            (responseData?.error) || 
            error.message || '';

          // 4. 检查错误消息是否包含禁用关键词
          if (errorMessage.includes('禁用') || 
              errorMessage.includes('disabled') || 
              errorMessage.includes('账号已被禁用')) {
            // 标记为禁用账户错误
            error.isDisabledAccount = true;
            error.disabledMessage = '账号已被禁用，请联系管理员';

            // 创建一个特定的错误对象，覆盖原始错误
            const disabledError = new Error('账号已被禁用，请联系管理员');
            disabledError.isDisabledAccount = true;
            disabledError.response = error.response;
            throw disabledError;
          }
        }

        // 继续抛出原始错误
        throw error;
      });
  }

  /**
   * 用户登出
   */
  logout() {
    localStorage.removeItem('user');
  }

  /**
   * 用户注册
   * @param {string} username 用户名
   * @param {string} email 邮箱
   * @param {string} password 密码
   * @returns {Promise} 注册结果
   */
  register(username, email, password) {
    return apiClient.post('/auth/signup', {
      username,
      email,
      password
    });
  }

  /**
   * 刷新Token
   * @returns {Promise} 刷新结果
   */
  refreshToken() {
    const user = this.getCurrentUser();
    if (!user || !user.refreshToken) {
      return Promise.reject(new Error('无效的刷新令牌'));
    }

    return apiClient.post('/auth/refresh-token', {
      refreshToken: user.refreshToken
    }).then(response => {
      if (response.token || response.accessToken) {
        // 更新本地存储中的用户信息
        const updatedUser = {
          ...user,
          token: response.token || response.accessToken,
          accessToken: response.token || response.accessToken
        };
        localStorage.setItem('user', JSON.stringify(updatedUser));
      }
      return response;
    });
  }

  /**
   * 检查用户是否为管理员
   * @returns {boolean} 是否为管理员
   */
  isAdmin() {
    const user = this.getCurrentUser();
    if (!user || !user.roles) return false;

    return Array.isArray(user.roles) 
      ? user.roles.includes('ROLE_ADMIN')
      : user.roles === 'ROLE_ADMIN';
  }

  /**
   * 获取当前用户信息
   * @returns {Object|null} 用户信息
   */
  getCurrentUser() {
    const userStr = localStorage.getItem('user');
    if (!userStr) return null;

    try {
      return JSON.parse(userStr);
    } catch (e) {
      console.error('解析用户信息失败:', e);
      return null;
    }
  }
}

export default new AuthService();

import axios from 'axios';

// 创建axios实例
const apiClient = axios.create({
  baseURL: process.env.VUE_APP_API_URL || 'http://localhost:8080',
  timeout: 10000,
  withCredentials: true,
  headers: {
    'Accept': 'application/json',
    'Content-Type': 'application/json'
  }
});

// 请求拦截器
apiClient.interceptors.request.use(
  config => {
    // 从localStorage获取token
    const userStr = localStorage.getItem('user');
    if (userStr) {
      try {
        const user = JSON.parse(userStr);
        const token = user.accessToken || user.token;
        if (token) {
          // 在请求头中添加token
          config.headers['Authorization'] = `Bearer ${token}`;
        }
      } catch (e) {
        // 解析失败时不添加token
      }
    }
    
    return config;
  },
  error => {
    return Promise.reject(error);
  }
);

// 响应拦截器
apiClient.interceptors.response.use(
  response => {
    return response.data;
  },
  error => {
    // 打印详细的错误信息以便调试
    console.log('API错误拦截器捕获到错误:', error);
    if (error.response) {
      console.log('错误响应详情:', {
        status: error.response.status,
        statusText: error.response.statusText,
        data: error.response.data
      });
    }
    
    // 判断是否是禁用账户错误的方式更全面
    const isDisabledAccount = (() => {
      // 1. 检查错误对象是否已被标记
      if (error.isDisabledAccount) return true;
      
      // 2. 如果没有响应，则不是禁用账户错误
      if (!error.response) return false;
      
      // 3. 检查响应数据
      const responseData = error.response.data;
      
      // 4. 尝试从多种数据格式中提取错误消息
      const errorMessage = 
        (typeof responseData === 'string' ? responseData : '') || 
        (responseData?.message) || 
        (responseData?.error) || 
        error.message || '';
      
      // 5. 只有明确包含禁用关键词才认为是禁用账户错误
      return (errorMessage.includes('禁用') || 
          errorMessage.includes('disabled') || 
          errorMessage.includes('账号已被禁用'));
    })();
    
    // 处理禁用账户错误
    if (isDisabledAccount) {
      console.log('检测到禁用账户错误');
      // 标记错误对象
      error.isDisabledAccount = true;
      error.disabledMessage = '账号已被禁用，请联系管理员';
      
      // 创建一个新的错误对象，添加自定义的message以便于UI层识别
      const disabledError = new Error('账号已被禁用，请联系管理员');
      disabledError.isDisabledAccount = true;
      disabledError.response = error.response;
      return Promise.reject(disabledError);
    }
    
    // 处理其他身份验证错误
    if (error.response && error.response.status === 401 && !isDisabledAccount) {
      // 非禁用导致的401错误，清除用户信息并重定向
      localStorage.removeItem('user');
      
      // 如果不在登录页面，重定向到登录页面
      if (window.location.pathname !== '/login') {
        window.location.href = '/login?redirect=' + encodeURIComponent(window.location.pathname);
      }
    }
    
    return Promise.reject(error);
  }
);

export default apiClient;

import apiClient from './api';

// 管理员相关的API服务
const adminService = {
  // 获取仪表盘统计数据
  async getDashboardStats() {
    return apiClient.get('/admin/dashboard');
  },

  // 获取所有用户列表
  async getAllUsers() {
    return apiClient.get('/admin/users');
  },

  // 获取用户详情
  async getUserDetail(userId) {
    if (!userId) {
      throw new Error('用户ID不能为空');
    }
    return apiClient.get(`/admin/users/${userId}`);
  },

  // 修改用户状态（启用/禁用）
  async updateUserStatus(userId, enabled) {
    if (!userId) {
      throw new Error('用户ID不能为空');
    }
    return apiClient.put(`/admin/users/${userId}/status`, { enabled });
  },

  // 修改用户信息（包括密码）
  async updateUserInfo(userId, userData) {
    if (!userId) {
      throw new Error('用户ID不能为空');
    }
    return apiClient.put(`/admin/users/${userId}`, userData);
  },

  // 删除用户
  async deleteUser(userId) {
    if (!userId) {
      throw new Error('用户ID不能为空');
    }
    return apiClient.delete(`/admin/users/${userId}`);
  },

  // 获取所有小说列表（管理员视图）
  async getAllNovels() {
    return apiClient.get('/admin/novels');
  },

  // 删除小说
  async deleteNovel(novelId) {
    if (!novelId) {
      throw new Error('小说ID不能为空');
    }
    return apiClient.delete(`/admin/novels/${novelId}`);
  },

  // 获取系统日志
  async getSystemLogs(page = 0, size = 20, filters = {}) {
    let url = `/admin/logs?page=${page}&size=${size}`;
    
    // 添加日志级别筛选
    if (filters.level && filters.level !== 'ALL') {
      url += `&level=${filters.level}`;
    }
    
    // 添加日期范围筛选
    if (filters.startDate) {
      url += `&startDate=${filters.startDate}`;
    }
    
    if (filters.endDate) {
      url += `&endDate=${filters.endDate}`;
    }
    
    // 添加搜索关键词
    if (filters.query) {
      url += `&query=${encodeURIComponent(filters.query)}`;
    }
    
    // 添加用户ID筛选
    if (filters.userId) {
      // 确保userId作为字符串传递
      url += `&userId=${String(filters.userId)}`;
    }
    
    // 输出完整URL供调试
    console.log('系统日志请求URL:', url);
    
    return apiClient.get(url);
  },

  // 清理系统缓存
  async clearSystemCache() {
    return apiClient.post('/admin/cache/clear');
  }
};

export default adminService;
